cd "C:/Users/EDY/AppData/Local/Temp/claude/D--nexgaios-amazon/75bfbc79-d177-409b-9ee2-61bd87ae42dd/scratchpad" && python - <<'PY'
import csv
rows=[]
with open('sqp_digests/sqp_brand_monthly.csv',encoding='utf-8') as f:
    for r in csv.DictReader(f): rows.append(r)
def num(x):
    try: return float(x)
    except: return 0.0
core={ r['month']: r for r in rows if r['uni']=='core'}
fj25=['2025-02','2025-03','2025-04','2025-05','2025-06']; fj26=['2026-02','2026-03','2026-04','2026-05','2026-06']
def wshare(months,my,mk): return sum(num(core[m][my]) for m in months)/sum(num(core[m][mk]) for m in months)*100
print("=== SQP core 4环份额 (sum my/sum mkt, Feb-Jun) ===")
for lbl,my,mk in [('imp','my_imp','mkt_imp'),('clk','my_clk','mkt_clk'),('atc','my_atc','mkt_atc'),('ord','my_ord','mkt_ord')]:
    s25=wshare(fj25,my,mk); s26=wshare(fj26,my,mk); print(f"{lbl}_share {s25:.2f}% -> {s26:.2f}%  d={s26-s25:+.2f}pp")
def sctr(months): return sum(num(core[m]['my_clk']) for m in months)/sum(num(core[m]['my_imp']) for m in months)*100
print(f"\n自家CTR(SQP my_clk/my_imp) Feb-Jun {sctr(fj25):.3f}% -> {sctr(fj26):.3f}% ({(sctr(fj26)/sctr(fj25)-1)*100:.0f}%)")
for m in ['2025-04','2025-05','2025-06','2026-04','2026-05','2026-06']:
    r=core[m]; print(f"  {m}: {num(r['my_clk'])/num(r['my_imp'])*100:.3f}%")
def mcvr(months): return sum(num(core[m]['mkt_ord']) for m in months)/sum(num(core[m]['mkt_sv']) for m in months)*100
print(f"\n市场CVR(SQP mkt_ord/mkt_sv) Feb-Jun {mcvr(fj25):.3f}% -> {mcvr(fj26):.3f}% d={mcvr(fj26)-mcvr(fj25):+.3f}pp")
for m in ['2025-06','2026-01','2026-02','2026-03','2026-04','2026-05','2026-06']:
    print(f"  {m}: ord_rate={core[m]['ord_rate']}")
PY
